function setSecurityValue(){if("home"!==window.dataPage)return;let e=document.querySelector('form dropmenu[data-type="security"]'),t=e.querySelector(".op-list li.active").getAttribute("data-option"),r=e.querySelector("input.random");r.setAttribute("name","d"),"cypher"===t?r.value=getRandom(0,93):"scrypto"===t?r.value=getRandomString(4):r.removeAttribute("name")}setSecurityValue();